SourceCode.Declaration:
[DataContractAttribute]
public class ETG_VendOpeningBalanceContract implements SysOperationValidatable
{
    TransDate    fromDate;
    TransDate    toDate;
    VendAccount  vendorAccount;

}

Method.Source:
[
    DataMemberAttribute('FromDate'),
    SysOperationLabelAttribute(literalStr("As On Date")),
    SysOperationHelpTextAttribute(literalStr("Enter the from date for opening balance"))
]
public TransDate parmFromDate(TransDate _fromDate = fromDate)
{
    fromDate = _fromDate;
    return fromDate;
}

[
    DataMemberAttribute('ToDate'),
    SysOperationLabelAttribute(literalStr("To Date")),
    SysOperationHelpTextAttribute(literalStr("Enter the to date for opening balance"))
]
public TransDate parmToDate(TransDate _toDate = toDate)
{
    toDate = _toDate;
    return toDate;
}

[
    DataMemberAttribute('VendorAccount'),
    SysOperationLabelAttribute(literalStr("Vendor Account")),
    SysOperationHelpTextAttribute(literalStr("Select the vendor account"))
]
public VendAccount parmVendorAccount(VendAccount _vendorAccount = vendorAccount)
{
    vendorAccount = _vendorAccount;
    return vendorAccount;
}

public boolean validate()
{


    boolean isValid = true;

    if (!fromDate)
    {
        isValid = checkFailed("As On Date is required.");
    }

    // Validation logic: As On Date must be today or earlier
    if (fromDate > today())
    {
        isValid = checkFailed("As On date cannot be greater than today date.");
    }

    return isValid;
}
